1: const Diacritic = enum(u8) {
2:   empty, // nguyên âm không dấu.
3:   circumflex, // dấu nón: â, ô, ê.
4:   horn, // dấu móc: ư, ơ.
5:   breve // dấu ă.
6: };
7: 
8: const Tone = enum(u8) {
9:   level, // thanh ngang, không dấu.
10:   rising, // sắc.
11:   falling, // huyền.
12:   dipping_rising, // hỏi.
13:   rising_glottalized, // ngã.
14:   falling_glottalized // nặng.
15: };
16: 
17: const Span = extern struct {
18:   base: u8, // alphabet ASCII character, could be lowercase or uppercase.
19:   diacritic: Diacritic = Diacritic.empty, // by default, it's plain alphabet character.
20:   tone: Tone = Tone.level // by default, no tone is placed.
21: };
22: 
23: const InputMode = enum(u8) {
24:   literal, // by pass Vietnamese input processing and append the character as is.
25:   telex // process Vietnamese input in Telex input method.
26: };
27: 
28: const State = extern struct {
29:   buffer_effective: [16]Span, // the effective buffer to process Vietnamese input. we will skip processing if the buffer longer than 16.
30:   buffer_length: u8, // the maximum buffer length that the engine still keeps the effective buffer, after the maximum value (256), we will reset the effective buffer and this value.
31:   literal_start_index: i8, // mark the position (inclusive) in buffer where we will switch to literal mode (due to manually switch, input cancellation, exceed effective buffer). This value is independent from mode and has higher priority, e.g. if the mode is `telex` but the engine is working on position on or after literal index, the engine will skip Vietnamese input processing (we only count positive value, -1 mean no literal index).
32:   mode: InputMode = InputMode.literal // determine if we will process input in the specified mode (Telex) or append the character as is.
33: };
